// ===== 質問解析 + DPro検索 + 回答生成 =====
const event = $input.first().json.body.event;
const userText = event.text || '';
const threadTs = event.thread_ts || event.ts;
const CHANNEL = event.channel || 'C0AMYLU2W5D';

const DPRO_BASE = 'https://YOUR_WORKER_NAME.workers.dev'; // ← Cloudflare WorkerのURLに変更

async function dproGet(path, params) {
  let qs = '';
  if (params) {
    const parts = [];
    for (const [k, v] of Object.entries(params)) {
      if (v != null) parts.push(encodeURIComponent(k) + '=' + encodeURIComponent(String(v)));
    }
    if (parts.length) qs = '?' + parts.join('&');
  }
  const fullUrl = DPRO_BASE + path + qs;
  const res = await $http.request({ method: 'GET', url: fullUrl });
  return res;
}

// 1. 本質思考: 質問からジャンル・媒体・タイプを抽出
const GENRE_MAP = [
  { labels: ['ヒザ', '膝', '関節'], q: 'ヒザ', name: 'ヒザ系' },
  { labels: ['毛穴', 'シミ', 'シワ', '美肌', '肌'], q: '毛穴', name: '毛穴/シミ/シワ' },
  { labels: ['子供', '成長', 'サプリ', '身長', '育ち'], q: '成長', name: '子供サプリ' },
  { labels: ['体臭', 'ワキガ', 'デオドラント', '臭い', 'におい'], q: '体臭', name: '女性体臭' }
];
const MEDIA_MAP = [
  { labels: ['Instagram', 'インスタ', 'IG', 'インスタグラム'], key: 'instagram' },
  { labels: ['YouTube', 'ユーチューブ', 'YT', 'ようつべ'], key: 'youtube' }
];
const QUERY_TYPES = {
  hook: ['フック', 'ナレーション', '冒頭', 'コピー', '文句', '言葉'],
  lp: ['LP', 'ランディング', '記事', '着地'],
  compare: ['比較', 'どっち', '比べ', 'vs'],
  trend: ['トレンド', '伸びてる', '人気', '最新', 'ランキング', 'TOP']
};

function detect(text, labels) {
  return labels.some(function(l) { return text.includes(l); });
}

// ジャンル検出
let detectedGenre = null;
for (const gm of GENRE_MAP) {
  if (detect(userText, gm.labels)) { detectedGenre = gm; break; }
}

// 媒体検出
let detectedMedias = [];
for (const mm of MEDIA_MAP) {
  if (detect(userText, mm.labels)) detectedMedias.push(mm.key);
}
if (detectedMedias.length === 0) detectedMedias = ['instagram', 'youtube'];

// クエリタイプ検出
let queryType = 'trend';
for (const [type, words] of Object.entries(QUERY_TYPES)) {
  if (detect(userText, words)) { queryType = type; break; }
}

// 2. DPro API検索
const appsRaw = await dproGet('/api/v1/apps');
const appList = Array.isArray(appsRaw) ? appsRaw : (appsRaw.data || []);
const mediaIds = {};
for (const app of appList) {
  const s = JSON.stringify(app);
  if (/instagram|facebook/i.test(s)) mediaIds['instagram'] = app.id || app.app_id;
  if (/youtube/i.test(s)) mediaIds['youtube'] = app.id || app.app_id;
}

let genreId = null;
if (detectedGenre) {
  try {
    const gr = await dproGet('/api/v1/genres', { q: detectedGenre.q });
    const gl = Array.isArray(gr) ? gr : (gr.data || gr.genres || []);
    genreId = gl.length > 0 ? (gl[0].id || gl[0].genre_id) : null;
  } catch(e) {}
}

const results = [];
for (const mediaKey of detectedMedias) {
  const appId = mediaIds[mediaKey];
  const params = { app_id: appId, sort: 'ad_cost_diff_desc', limit: 5 };
  if (genreId) params.genre_id = genreId;
  try {
    const r = await dproGet('/api/v1/items', params);
    const items = Array.isArray(r) ? r : (r.data || r.items || []);
    results.push({ media: mediaKey === 'instagram' ? '📸Instagram' : '🎬YouTube', items: items });
  } catch(e) {
    results.push({ media: mediaKey === 'instagram' ? '📸Instagram' : '🎬YouTube', items: [] });
  }
}

// 3. 本質思考: 回答文を組み立て
const genreName = detectedGenre ? detectedGenre.name : '全ジャンル';
const mediaNames = results.map(function(r) { return r.media; }).join(' & ');

const lines = [];
lines.push('おっ、いい質問！🔍');
lines.push('*【質問の本質】* ' + genreName + ' × ' + mediaNames + ' の直近トレンドですね。調べました！');
lines.push('');

for (const result of results) {
  if (!result.items.length) {
    lines.push('*' + result.media + '*: 該当データなし');
    continue;
  }
  lines.push('*' + result.media + ' × ' + genreName + '* 直近30日 TOP' + Math.min(result.items.length, 3));
  result.items.slice(0, 3).forEach(function(item, i) {
    const name = item.product_name || item.name || '商品名不明';
    const diff = Number(item.ad_cost_diff || item.ad_cost_diff_30d || 0);
    const diffStr = diff >= 1000000
      ? '▲¥' + (diff / 1000000).toFixed(1) + 'M'
      : '▲¥' + (diff / 1000).toFixed(0) + 'K';
    lines.push((i + 1) + '. ' + diffStr + '｜' + name);
    if (queryType === 'hook') {
      const hook = item.narration_text || item.copy_text || item.description || '';
      if (hook) lines.push('   💬 「' + hook.slice(0, 60) + (hook.length > 60 ? '…' : '') + '」');
    }
  });
  lines.push('');
}

// パターン分析（TOP3のフックから傾向を抽出）
const allItems = results.flatMap(function(r) { return r.items.slice(0, 3); });
lines.push('*💡 解釈・示唆*');
lines.push(genreName + 'では現在、上位広告が集中して配信されています。');
lines.push('より深く調べる場合は「' + genreName + ' LPのコピーを見せて」などもOKです！');

return [{ json: { slackReply: { channel: CHANNEL, thread_ts: threadTs, text: lines.join('\n') } } }];
